  display: inline-block;
  font-size: 15px;
  font-style: normal;
  font-weight: 700;
  line-height: 16px;
  padding: 5px 14px;
  text-decoration: none;
}

.con-button:hover {
  background-color: var(--color-black);
  border-color: var(--color-black);
  color: var(--color-white);
  text-decoration: none;
}

.l-button .con-button,
.con-button.button-l {
  border-radius: 20px;
  font-size: 17px;
  line-height: 20px;
  min-height: 21px;
  padding: 7px 18px 8px;
}

.xl-button .con-button,
