</style><style id="inline-verb-widget-styles">:root {
  /* Consonant Variables */
  --consonant-font-family:'Adobe Clean', adobe-clean, 'Trebuchet MS', sans-serif;
  --consonant-color-white: #FFF;
  --consonant-color: #2C2C2C;
