.verb-widget .milo-tooltip::before {
  content: attr(data-tooltip);
  position: absolute;
  top: 50%;
  transform: translateY(-50%);
  left: 100%;
  margin-left: 7px;
  max-width: 140px;
  padding: 10px;
  border-radius: 5px;
